// ============================================
// FUNCIONES DE FILTRADO Y SELECCIÓN
// ============================================

// Obtener palabras que aún no han sido usadas
function getUnusedWords(usedWordsArray) {
    const usedWordsList = usedWordsArray.map(w => w.word.toLowerCase());
    return WORD_DICTIONARY.filter(word => !usedWordsList.includes(word.word.toLowerCase()));
}

// Verificar si quedan palabras disponibles
function hasAvailableWords(usedWordsArray) {
    return getUnusedWords(usedWordsArray).length > 0;
}

// Obtener palabra aleatoria de las no usadas
function getRandomUnusedWord(usedWordsArray) {
    const unusedWords = getUnusedWords(usedWordsArray);
    if (unusedWords.length === 0) return null;
    
    const randomIndex = Math.floor(Math.random() * unusedWords.length);
    return unusedWords[randomIndex];
}

// Exportar funciones y diccionario
if (typeof window !== 'undefined') {
    window.WORD_DICTIONARY = WORD_DICTIONARY;
    window.getUnusedWords = getUnusedWords;
    window.hasAvailableWords = hasAvailableWords;
    window.getRandomUnusedWord = getRandomUnusedWord;
}

console.log('✅ Diccionario cargado:', WORD_DICTIONARY.length, 'palabras');
